const css = "/* ═══════════════════════════════════════════════════\n   POKÉINVEST — DESIGN SYSTEM v2 · App Edition\n   ═══════════════════════════════════════════════════ */\n\n/* ===== TOKENS ===== */\n:root {\n    --red:         #E3350D;\n    --red-hover:   #C72B09;\n    --red-glow:    rgba(227,53,13,.18);\n    --red-dim:     rgba(227,53,13,.10);\n    --gold:        #F5B800;\n    --gold-text:   #7A5C00;\n    --gold-dim:    rgba(245,184,0,.12);\n    --blue:        #2557C7;\n    --blue-hover:  #1D46A8;\n    --blue-dim:    rgba(37,87,199,.10);\n    --navy:        #0B1623;\n    --navy-mid:    rgba(11,22,35,.7);\n    --surface:     #F0F2F8;\n    --card:        #FFFFFF;\n    --border:      rgba(0,0,0,.07);\n    --border-mid:  rgba(0,0,0,.11);\n    --muted:       #6B7280;\n    --muted-light: #9CA3AF;\n    --success:     #059669;\n    --success-bg:  rgba(5,150,105,.09);\n    --danger:      #DC2626;\n    --danger-bg:   rgba(220,38,38,.08);\n    --text:        #111827;\n    --text-2:      #374151;\n    --sidebar-w:   264px;\n\n    --r-xs: 6px;\n    --r-sm: 10px;\n    --r:    14px;\n    --r-lg: 18px;\n    --r-xl: 22px;\n\n    --sh-sm: 0 1px 3px rgba(0,0,0,.06), 0 1px 2px rgba(0,0,0,.04);\n    --sh:    0 4px 20px rgba(0,0,0,.08), 0 1px 4px rgba(0,0,0,.04);\n    --sh-lg: 0 12px 40px rgba(0,0,0,.11), 0 4px 12px rgba(0,0,0,.06);\n    --sh-xl: 0 24px 60px rgba(0,0,0,.16), 0 8px 20px rgba(0,0,0,.08);\n\n    /* Easing app-like */\n    --spring: cubic-bezier(0.34, 1.56, 0.64, 1);\n    --ease-out: cubic-bezier(0.16, 1, 0.3, 1);\n    --ease-in-out: cubic-bezier(0.45, 0, 0.55, 1);\n}\n\n/* ===== DARK MODE TOKENS ===== */\n[data-theme=\"dark\"] {\n    --surface:     #0f1923;\n    --card:        #172030;\n    --border:      rgba(255,255,255,.07);\n    --border-mid:  rgba(255,255,255,.11);\n    --muted:       #8b95a3;\n    --muted-light: #5c6775;\n    --text:        #e8edf3;\n    --text-2:      #b0bac6;\n    --gold-text:   #F5B800;\n    --blue-dim:    rgba(37,87,199,.18);\n    --red-dim:     rgba(227,53,13,.15);\n    --red-glow:    rgba(227,53,13,.22);\n    --gold-dim:    rgba(245,184,0,.14);\n    --success-bg:  rgba(5,150,105,.14);\n    --danger-bg:   rgba(220,38,38,.12);\n    --sh-sm: 0 1px 3px rgba(0,0,0,.24), 0 1px 2px rgba(0,0,0,.18);\n    --sh:    0 4px 20px rgba(0,0,0,.32), 0 1px 4px rgba(0,0,0,.18);\n    --sh-lg: 0 12px 40px rgba(0,0,0,.44), 0 4px 12px rgba(0,0,0,.24);\n    --sh-xl: 0 24px 60px rgba(0,0,0,.60), 0 8px 20px rgba(0,0,0,.32);\n}\n\n/* ===== RESET ===== */\n@media (prefers-reduced-motion: reduce) {\n    *, *::before, *::after {\n        animation-duration: .01ms !important;\n        transition-duration: .01ms !important;\n    }\n}\n*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\nhtml { scroll-behavior: smooth; }\n\nbody {\n    font-family: 'Manrope', system-ui, sans-serif;\n    background: var(--surface);\n    color: var(--text);\n    display: flex;\n    min-height: 100vh;\n    line-height: 1.6;\n    -webkit-font-smoothing: antialiased;\n    -moz-osx-font-smoothing: grayscale;\n}\n\n/* Scrollbar custom */\n::-webkit-scrollbar { width: 6px; height: 6px; }\n::-webkit-scrollbar-track { background: transparent; }\n::-webkit-scrollbar-thumb { background: rgba(0,0,0,.15); border-radius: 99px; }\n::-webkit-scrollbar-thumb:hover { background: rgba(0,0,0,.25); }\n\n:focus-visible {\n    outline: 2px solid var(--blue);\n    outline-offset: 3px;\n    border-radius: var(--r-xs);\n}\n\n/* ═══════════════════════ PAGE TRANSITION ═══════════════════════ */\n.main {\n    animation: pageIn .3s var(--ease-out) both;\n}\n@keyframes pageIn {\n    from { opacity: 0; transform: translateY(10px); }\n    to   { opacity: 1; transform: translateY(0); }\n}\n\n/* ═══════════════════════ SIDEBAR ═══════════════════════ */\n.sidebar {\n    width: var(--sidebar-w);\n    background: linear-gradient(180deg, #0e1c2e 0%, #0B1623 50%);\n    position: fixed;\n    top: 0; left: 0;\n    height: 100vh;\n    display: flex;\n    flex-direction: column;\n    z-index: 50;\n    border-right: 1px solid rgba(255,255,255,.04);\n    box-shadow: 6px 0 32px rgba(0,0,0,.22);\n    transition: transform .3s var(--ease-out);\n}\n\n.sidebar-logo {\n    padding: 22px 18px 18px;\n    border-bottom: 1px solid rgba(255,255,255,.06);\n}\n\n.logo-mark {\n    display: flex; align-items: center; gap: 11px;\n    text-decoration: none;\n}\n\n.logo-ball {\n    width: 38px; height: 38px;\n    border-radius: 50%;\n    background: conic-gradient(var(--red) 50%, #fff 50%);\n    position: relative;\n    flex-shrink: 0;\n    box-shadow: 0 0 0 2.5px rgba(255,255,255,.12), 0 4px 16px rgba(227,53,13,.22);\n    transition: transform .2s var(--spring), box-shadow .2s;\n}\n.logo-ball:hover { transform: rotate(15deg) scale(1.05); box-shadow: 0 0 0 2.5px rgba(255,255,255,.2), 0 6px 20px rgba(227,53,13,.3); }\n.logo-ball::before {\n    content: '';\n    position: absolute;\n    top: 50%; left: 0; right: 0;\n    height: 2px;\n    background: rgba(0,0,0,.18);\n    transform: translateY(-50%);\n}\n.logo-ball::after {\n    content: '';\n    position: absolute;\n    top: 50%; left: 50%;\n    transform: translate(-50%,-50%);\n    width: 11px; height: 11px;\n    border-radius: 50%;\n    background: white;\n    border: 1.5px solid rgba(0,0,0,.1);\n    box-shadow: 0 1px 3px rgba(0,0,0,.2);\n}\n\n.logo-text {\n    font-size: 17px;\n    font-weight: 800;\n    color: var(--gold);\n    letter-spacing: -.3px;\n    line-height: 1.15;\n}\n.logo-text span {\n    display: block;\n    font-size: 9.5px;\n    font-weight: 500;\n    color: rgba(255,255,255,.22);\n    letter-spacing: 1.4px;\n    text-transform: uppercase;\n    margin-top: 2px;\n}\n\n/* Nav */\n.nav { padding: 8px 10px; flex: 1; overflow-y: auto; scrollbar-width: none; }\n.nav::-webkit-scrollbar { display: none; }\n\n.nav-section {\n    padding: 16px 10px 5px;\n    font-size: 9.5px;\n    font-weight: 700;\n    letter-spacing: 1.4px;\n    text-transform: uppercase;\n    color: rgba(255,255,255,.16);\n}\n\n.nav a {\n    display: flex;\n    align-items: center;\n    gap: 11px;\n    padding: 9px 12px;\n    color: rgba(255,255,255,.42);\n    text-decoration: none;\n    font-size: 13.5px;\n    font-weight: 500;\n    transition: color .18s, background .18s, transform .1s;\n    border-radius: var(--r-sm);\n    position: relative;\n    margin-bottom: 2px;\n    cursor: pointer;\n    -webkit-tap-highlight-color: transparent;\n}\n\n.nav-icon {\n    width: 32px; height: 32px;\n    border-radius: 8px;\n    display: flex; align-items: center; justify-content: center;\n    flex-shrink: 0;\n    background: rgba(255,255,255,.05);\n    transition: background .18s, transform .15s var(--spring);\n}\n.nav-icon svg { width: 15px; height: 15px; transition: stroke .18s; }\n\n.nav a:hover {\n    color: rgba(255,255,255,.88);\n    background: rgba(255,255,255,.07);\n}\n.nav a:hover .nav-icon {\n    background: rgba(255,255,255,.10);\n    transform: scale(1.08);\n}\n.nav a:active { transform: scale(.97); }\n\n.nav a.active {\n    color: white;\n    background: rgba(227,53,13,.14);\n    font-weight: 600;\n}\n.nav a.active .nav-icon {\n    background: rgba(227,53,13,.22);\n    color: #ff7a5a;\n    transform: none;\n}\n.nav a.active::before {\n    content: '';\n    position: absolute;\n    left: 0; top: 5px; bottom: 5px;\n    width: 3px;\n    background: linear-gradient(180deg, var(--red), #ff8060);\n    border-radius: 0 3px 3px 0;\n    box-shadow: 2px 0 8px rgba(227,53,13,.4);\n}\n\n/* Sidebar footer */\n.sidebar-footer {\n    padding: 12px 14px 16px;\n    border-top: 1px solid rgba(255,255,255,.06);\n}\n.user-pill {\n    display: flex;\n    align-items: center;\n    gap: 10px;\n    background: rgba(255,255,255,.05);\n    border-radius: var(--r-sm);\n    padding: 9px 11px;\n    transition: background .18s;\n    cursor: pointer;\n    border: 1px solid rgba(255,255,255,.04);\n}\n.user-pill:hover { background: rgba(255,255,255,.09); }\n.user-avatar {\n    width: 32px; height: 32px;\n    border-radius: 50%;\n    background: linear-gradient(135deg, var(--red), var(--gold));\n    display: flex; align-items: center; justify-content: center;\n    font-weight: 700; font-size: 13px; color: white;\n    flex-shrink: 0;\n    box-shadow: 0 2px 8px rgba(227,53,13,.25);\n}\n.user-name { font-size: 13px; font-weight: 600; color: rgba(255,255,255,.85); }\n.user-role { font-size: 11px; color: rgba(255,255,255,.22); }\n\n/* ═══════════════════════ MAIN ═══════════════════════ */\n.main {\n    margin-left: var(--sidebar-w);\n    flex: 1;\n    padding: 36px 40px;\n    max-width: calc(100vw - var(--sidebar-w));\n}\n\n/* ===== PAGE HEADER ===== */\n.page-header {\n    display: flex;\n    justify-content: space-between;\n    align-items: center;\n    margin-bottom: 28px;\n}\n\n.page-title {\n    font-size: 26px;\n    font-weight: 800;\n    color: var(--text);\n    letter-spacing: -.6px;\n    line-height: 1.1;\n}\n.page-subtitle {\n    font-size: 13px;\n    color: var(--muted);\n    margin-top: 5px;\n    font-weight: 500;\n}\n\n.date-badge {\n    background: var(--card);\n    border: 1px solid var(--border);\n    border-radius: var(--r-sm);\n    padding: 7px 14px;\n    font-size: 12px;\n    color: var(--muted);\n    font-weight: 500;\n    box-shadow: var(--sh-sm);\n    white-space: nowrap;\n}\n\n/* ═══════════════════════ STAT CARDS ═══════════════════════ */\n.stats-grid {\n    display: grid;\n    grid-template-columns: repeat(4, 1fr);\n    gap: 14px;\n    margin-bottom: 24px;\n}\n\n.stat-card {\n    background: var(--card);\n    border-radius: var(--r-lg);\n    padding: 20px 20px 18px;\n    border: 1px solid var(--border);\n    position: relative;\n    overflow: hidden;\n    transition: box-shadow .22s var(--ease-out), transform .22s var(--ease-out);\n    box-shadow: var(--sh-sm);\n    cursor: default;\n}\n.stat-card:hover {\n    transform: translateY(-3px);\n    box-shadow: var(--sh);\n}\n\n.stat-card::after {\n    content: '';\n    position: absolute;\n    top: 0; left: 0; right: 0;\n    height: 3px;\n    border-radius: var(--r-lg) var(--r-lg) 0 0;\n}\n.stat-card.c-blue::after  { background: linear-gradient(90deg, var(--blue), #6b9bff); }\n.stat-card.c-gold::after  { background: linear-gradient(90deg, #d49c00, var(--gold)); }\n.stat-card.c-green::after { background: linear-gradient(90deg, var(--success), #34d399); }\n.stat-card.c-red::after   { background: linear-gradient(90deg, var(--red), #ff7a5a); }\n\n.stat-card.c-blue  { background: linear-gradient(150deg, #fff 55%, rgba(37,87,199,.05)); }\n.stat-card.c-gold  { background: linear-gradient(150deg, #fff 55%, rgba(245,184,0,.06)); }\n.stat-card.c-green { background: linear-gradient(150deg, #fff 55%, rgba(5,150,105,.05)); }\n.stat-card.c-red   { background: linear-gradient(150deg, #fff 55%, rgba(227,53,13,.05)); }\n\n.stat-card-top {\n    display: flex;\n    justify-content: space-between;\n    align-items: flex-start;\n    margin-bottom: 12px;\n}\n.stat-label {\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .5px;\n    text-transform: uppercase;\n    color: var(--muted);\n}\n.stat-icon-wrap {\n    width: 36px; height: 36px;\n    border-radius: var(--r-sm);\n    display: flex; align-items: center; justify-content: center;\n    flex-shrink: 0;\n    transition: transform .2s var(--spring);\n}\n.stat-card:hover .stat-icon-wrap { transform: scale(1.1) rotate(-5deg); }\n.stat-icon-wrap svg { width: 17px; height: 17px; }\n.c-blue  .stat-icon-wrap { background: var(--blue-dim); color: var(--blue); }\n.c-gold  .stat-icon-wrap { background: var(--gold-dim); color: #b08a00; }\n.c-green .stat-icon-wrap { background: var(--success-bg); color: var(--success); }\n.c-red   .stat-icon-wrap { background: var(--red-dim); color: var(--red); }\n\n.stat-value {\n    font-size: 26px;\n    font-weight: 800;\n    color: var(--text);\n    letter-spacing: -.5px;\n    line-height: 1;\n    font-variant-numeric: tabular-nums lining-nums;\n}\n.stat-value.positive { color: var(--success); }\n.stat-value.warning  { color: #a07800; }\n\n.stat-footer {\n    margin-top: 8px;\n    font-size: 11.5px;\n    color: var(--muted-light);\n    font-weight: 500;\n}\n\n/* ═══════════════════════ CHARTS ═══════════════════════ */\n.charts-row {\n    display: grid;\n    grid-template-columns: 3fr 2fr;\n    gap: 14px;\n}\n\n.panel {\n    background: var(--card);\n    border-radius: var(--r-lg);\n    border: 1px solid var(--border);\n    padding: 24px;\n    box-shadow: var(--sh-sm);\n    transition: box-shadow .22s;\n}\n.panel:hover { box-shadow: var(--sh); }\n\n.panel-header {\n    display: flex;\n    justify-content: space-between;\n    align-items: center;\n    margin-bottom: 20px;\n}\n.panel-title { font-size: 14px; font-weight: 700; color: var(--text); }\n.panel-badge {\n    font-size: 11px; font-weight: 600;\n    background: var(--gold-dim); color: var(--gold-text);\n    padding: 3px 10px; border-radius: 20px;\n    border: 1px solid rgba(245,184,0,.18);\n}\n.chart-wrap { height: 260px; position: relative; }\n\n/* ===== TOP PERFORMERS ===== */\n.performer-list { list-style: none; }\n.performer-item {\n    display: flex;\n    justify-content: space-between;\n    align-items: center;\n    padding: 10px 0;\n    border-bottom: 1px solid var(--border);\n    transition: background .15s;\n    border-radius: var(--r-xs);\n    margin: 0 -6px; padding-left: 6px; padding-right: 6px;\n}\n.performer-item:first-child { padding-top: 0; }\n.performer-item:last-child { border-bottom: none; }\n.performer-item:hover { background: #F8F9FF; }\n\n.performer-rank { font-size: 11px; font-weight: 700; color: var(--muted-light); width: 22px; flex-shrink: 0; font-variant-numeric: tabular-nums; }\n.performer-rank.top { color: #a07800; }\n.performer-info { flex: 1; padding: 0 12px; }\n.performer-name { font-size: 13px; font-weight: 600; color: var(--text-2); }\n.performer-cat { font-size: 11.5px; color: var(--muted-light); margin-top: 1px; }\n.performer-gain {\n    font-size: 12px; font-weight: 700; color: var(--success);\n    background: var(--success-bg); padding: 3px 9px; border-radius: 20px;\n    white-space: nowrap; border: 1px solid rgba(5,150,105,.10);\n    font-variant-numeric: tabular-nums lining-nums;\n}\n.performer-gain.negative-gain {\n    color: var(--danger);\n    background: var(--danger-bg);\n    border-color: rgba(220,38,38,.10);\n}\n\n/* ═══════════════════════ TOP BAR ═══════════════════════ */\n.top-bar {\n    display: flex;\n    justify-content: space-between;\n    align-items: center;\n    margin-bottom: 16px;\n    gap: 14px;\n}\n\n.search-wrap { position: relative; flex: 1; max-width: 440px; }\n.search-icon {\n    position: absolute; left: 12px; top: 50%;\n    transform: translateY(-50%);\n    color: var(--muted-light); pointer-events: none;\n    display: flex; align-items: center;\n    transition: color .15s;\n}\n.search-icon svg { width: 15px; height: 15px; }\n.search-wrap input {\n    width: 100%; padding: 10px 14px 10px 38px;\n    border: 1.5px solid var(--border); border-radius: var(--r-sm);\n    font-family: 'Manrope', system-ui, sans-serif; font-size: 14px;\n    background: var(--card); color: var(--text); outline: none;\n    transition: border-color .18s, box-shadow .18s;\n    box-shadow: var(--sh-sm);\n}\n.search-wrap input:focus {\n    border-color: var(--blue);\n    box-shadow: 0 0 0 3px var(--blue-dim);\n}\n.search-wrap input:focus + .search-icon,\n.search-wrap:focus-within .search-icon { color: var(--blue); }\n.search-wrap input::placeholder { color: var(--muted-light); }\n\n.bar-right { display: flex; align-items: center; gap: 10px; }\n\n.count-badge {\n    background: var(--navy); color: rgba(255,255,255,.78);\n    padding: 7px 14px; border-radius: var(--r-xs);\n    font-size: 12px; font-weight: 600;\n    white-space: nowrap; font-variant-numeric: tabular-nums;\n}\n\n/* ===== BUTTONS ===== */\n.btn-add {\n    display: flex; align-items: center; gap: 7px;\n    background: var(--red); color: white; border: none;\n    padding: 10px 18px; border-radius: var(--r-sm);\n    font-family: 'Manrope', system-ui, sans-serif; font-size: 13px; font-weight: 700;\n    cursor: pointer;\n    transition: background .15s, transform .12s var(--spring), box-shadow .15s;\n    box-shadow: 0 2px 10px rgba(227,53,13,.28);\n    white-space: nowrap;\n    -webkit-tap-highlight-color: transparent;\n}\n.btn-add:hover {\n    background: var(--red-hover);\n    transform: translateY(-1px);\n    box-shadow: 0 4px 16px rgba(227,53,13,.34);\n}\n.btn-add:active { transform: scale(.96); box-shadow: 0 1px 6px rgba(227,53,13,.2); }\n.btn-add svg { width: 15px; height: 15px; }\n\n/* ═══════════════════════ TABLE ═══════════════════════ */\n.table-wrap {\n    background: var(--card);\n    border-radius: var(--r-lg);\n    border: 1px solid var(--border);\n    overflow: hidden;\n    box-shadow: var(--sh-sm);\n}\n\ntable { width: 100%; border-collapse: collapse; text-align: left; }\nthead tr { border-bottom: 2px solid rgba(0,0,0,.055); }\nth {\n    padding: 12px 16px;\n    font-size: 10.5px; font-weight: 700;\n    letter-spacing: .6px; text-transform: uppercase;\n    color: var(--muted); background: #F6F8FC;\n    cursor: pointer; user-select: none; white-space: nowrap;\n    transition: color .15s, background .15s;\n}\nth:hover { color: var(--blue); background: #EEF2FA; }\nth.sort-asc::after  { content: ' ▲'; font-size: .72em; opacity: .55; }\nth.sort-desc::after { content: ' ▼'; font-size: .72em; opacity: .55; }\nth[style*=\"cursor:default\"]:hover { color: var(--muted); background: #F6F8FC; }\n\ntbody tr {\n    border-bottom: 1px solid var(--border);\n    transition: background .12s;\n    cursor: default;\n}\ntbody tr:last-child { border-bottom: none; }\ntbody tr:hover { background: #F5F7FF; }\n\ntd { padding: 13px 16px; font-size: 14px; }\n\n.name-cell { font-weight: 600; color: var(--text); }\n.num-badge {\n    font-size: 11px; color: var(--muted);\n    background: #EEF0F7; padding: 2px 8px;\n    border-radius: 5px; font-variant-numeric: tabular-nums;\n    letter-spacing: .2px; white-space: nowrap;\n}\n\n.bloc-chip {\n    display: inline-block; padding: 3px 10px; border-radius: 6px;\n    font-size: 11px; font-weight: 600; letter-spacing: .2px;\n    white-space: nowrap;\n}\n.bloc-chip.ev   { background: rgba(5,150,105,.09); color: #047857; }\n.bloc-chip.eb   { background: var(--blue-dim); color: var(--blue); }\n.bloc-chip.me   { background: var(--gold-dim); color: #9a7200; }\n.bloc-chip.other{ background: #EEF0F7; color: var(--muted); }\n\n.price-cell {\n    font-weight: 700; font-size: 14px;\n    font-variant-numeric: tabular-nums lining-nums;\n}\n.positive { color: var(--success); font-weight: 700; font-variant-numeric: tabular-nums lining-nums; }\n.negative { color: var(--danger); font-weight: 700; font-variant-numeric: tabular-nums lining-nums; }\n.neutral  { color: var(--muted); font-weight: 500; }\n\n.actions { display: flex; gap: 4px; justify-content: flex-end; }\n.act-btn {\n    background: none; border: none;\n    width: 32px; height: 32px;\n    border-radius: var(--r-xs);\n    cursor: pointer;\n    display: flex; align-items: center; justify-content: center;\n    transition: background .12s, color .12s, transform .1s var(--spring);\n    color: var(--muted-light);\n    -webkit-tap-highlight-color: transparent;\n}\n.act-btn svg { width: 15px; height: 15px; }\n.act-btn:hover { transform: scale(1.12); }\n.act-btn:active { transform: scale(.92); }\n.act-btn.edit:hover { background: #EEF4FF; color: var(--blue); }\n.act-btn.del:hover  { background: var(--danger-bg); color: var(--danger); }\n\n/* ===== NOTE BADGE (PCA) ===== */\n.note-badge {\n    display: inline-flex; align-items: center; justify-content: center;\n    width: 36px; height: 24px; border-radius: 6px;\n    font-size: 12px; font-weight: 700;\n    background: #EEF0F7; color: var(--muted); margin: 0 auto;\n    font-variant-numeric: tabular-nums;\n}\n.note-badge.note-high { background: var(--success-bg); color: var(--success); border: 1px solid rgba(5,150,105,.15); }\n.note-badge.note-mid  { background: var(--gold-dim); color: #9a7200; border: 1px solid rgba(245,184,0,.18); }\n\n/* ===== ÉTAT VIDE ===== */\n.empty-state { text-align: center; padding: 72px 20px; color: var(--muted); }\n.empty-state .empty-icon { margin-bottom: 14px; opacity: .35; }\n.empty-state .empty-icon svg { width: 44px; height: 44px; stroke: var(--muted-light); }\n.empty-state p { font-size: 14px; color: var(--muted-light); font-weight: 500; }\n\n/* ═══════════════════════ MODAL ═══════════════════════ */\n.modal-overlay {\n    position: fixed; inset: 0;\n    background: rgba(11,22,35,.4);\n    display: flex; align-items: center; justify-content: center;\n    z-index: 200; opacity: 0; pointer-events: none;\n    transition: opacity .22s;\n    backdrop-filter: blur(8px);\n    -webkit-backdrop-filter: blur(8px);\n}\n.modal-overlay.active { opacity: 1; pointer-events: auto; }\n\n.modal {\n    background: var(--card);\n    border-radius: var(--r-xl);\n    padding: 30px;\n    width: 500px; max-width: 95vw;\n    box-shadow: var(--sh-xl);\n    transform: translateY(-16px) scale(.97);\n    transition: transform .28s var(--spring);\n    border: 1px solid rgba(255,255,255,.9);\n}\n.modal-overlay.active .modal { transform: translateY(0) scale(1); }\n\n.modal-head {\n    display: flex; justify-content: space-between; align-items: center;\n    margin-bottom: 22px; padding-bottom: 16px;\n    border-bottom: 1px solid var(--border);\n}\n.modal-title { font-size: 18px; font-weight: 800; color: var(--text); letter-spacing: -.3px; }\n.modal-close {\n    background: none; border: none;\n    width: 30px; height: 30px; border-radius: var(--r-xs); cursor: pointer;\n    color: var(--muted-light);\n    display: flex; align-items: center; justify-content: center;\n    transition: background .12s, color .12s, transform .1s var(--spring);\n}\n.modal-close:hover { background: var(--danger-bg); color: var(--danger); transform: rotate(90deg); }\n.modal-close svg { width: 16px; height: 16px; }\n\n.form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }\n.form-row.wide { grid-template-columns: 2fr 1fr; }\n.form-group { margin-bottom: 14px; }\n.form-group label {\n    display: block; font-size: 11px; font-weight: 700;\n    color: var(--muted); margin-bottom: 6px;\n    letter-spacing: .5px; text-transform: uppercase;\n}\n.form-group input,\n.form-group select {\n    width: 100%; padding: 9px 12px;\n    border: 1.5px solid var(--border); border-radius: var(--r-xs);\n    font-family: 'Manrope', system-ui, sans-serif; font-size: 14px;\n    color: var(--text); outline: none;\n    transition: border-color .18s, box-shadow .18s;\n    background: #fafbfd; appearance: none;\n}\n.form-group input:focus,\n.form-group select:focus {\n    border-color: var(--blue);\n    box-shadow: 0 0 0 3px var(--blue-dim);\n    background: var(--card);\n}\n\n.form-actions { display: flex; justify-content: flex-end; gap: 8px; margin-top: 20px; }\n.btn-cancel {\n    background: #EEF0F7; border: none;\n    padding: 9px 17px; border-radius: var(--r-xs);\n    font-family: 'Manrope', system-ui, sans-serif; font-size: 13px; font-weight: 600;\n    cursor: pointer; color: var(--muted);\n    transition: background .12s, transform .1s;\n}\n.btn-cancel:hover { background: #E4E6ED; }\n.btn-cancel:active { transform: scale(.96); }\n.btn-submit {\n    background: var(--blue); color: white; border: none;\n    padding: 9px 20px; border-radius: var(--r-xs);\n    font-family: 'Manrope', system-ui, sans-serif; font-size: 13px; font-weight: 700;\n    cursor: pointer;\n    transition: background .15s, box-shadow .15s, transform .1s var(--spring);\n    box-shadow: 0 2px 10px rgba(37,87,199,.24);\n}\n.btn-submit:hover { background: var(--blue-hover); box-shadow: 0 4px 14px rgba(37,87,199,.32); }\n.btn-submit:active { transform: scale(.96); }\n\n/* ===== EBAY ===== */\n.act-btn.ebay { color: #7c3aed; }\n.act-btn.ebay:hover { background: #f5f3ff; color: #7c3aed; }\n.act-btn.ebay.loading svg { animation: spin .7s linear infinite; }\n.act-btn.ebay.success { color: var(--success); }\n.act-btn.ebay.error { color: var(--danger); }\n\n@keyframes spin {\n    from { transform: rotate(0deg); }\n    to   { transform: rotate(360deg); }\n}\n\n.ebay-tooltip {\n    position: fixed;\n    background: #0B1623; color: white;\n    font-size: 12px; padding: 10px 14px;\n    border-radius: 10px; z-index: 1000;\n    pointer-events: none; opacity: 0;\n    transition: opacity .15s;\n    max-width: 260px; line-height: 1.5;\n    box-shadow: 0 6px 24px rgba(0,0,0,.28);\n    border: 1px solid rgba(255,255,255,.06);\n}\n.ebay-tooltip.visible { opacity: 1; }\n.ebay-tooltip .tt-price { font-size: 15px; font-weight: 700; color: var(--gold); font-variant-numeric: tabular-nums lining-nums; }\n.ebay-tooltip .tt-count { font-size: 11px; color: rgba(255,255,255,.4); margin-top: 2px; }\n\n/* ═══════════════════════ DARK MODE OVERRIDES ═══════════════════════ */\n[data-theme=\"dark\"] body { background: var(--surface); color: var(--text); }\n\n/* Stat cards — écrase les gradients hardcodés #fff */\n[data-theme=\"dark\"] .stat-card.c-blue  { background: linear-gradient(150deg, #172030 55%, rgba(37,87,199,.12)); }\n[data-theme=\"dark\"] .stat-card.c-gold  { background: linear-gradient(150deg, #172030 55%, rgba(245,184,0,.10)); }\n[data-theme=\"dark\"] .stat-card.c-green { background: linear-gradient(150deg, #172030 55%, rgba(5,150,105,.10)); }\n[data-theme=\"dark\"] .stat-card.c-red   { background: linear-gradient(150deg, #172030 55%, rgba(227,53,13,.10)); }\n[data-theme=\"dark\"] .stat-value.warning { color: var(--gold); }\n\n/* Table */\n[data-theme=\"dark\"] thead tr { border-bottom-color: rgba(255,255,255,.07); }\n[data-theme=\"dark\"] th { background: #1a2840; color: var(--muted); }\n[data-theme=\"dark\"] th:hover { background: #1e3050; color: #93b4ff; }\n[data-theme=\"dark\"] th[style*=\"cursor:default\"]:hover { background: #1a2840; color: var(--muted); }\n[data-theme=\"dark\"] tbody tr:hover { background: rgba(255,255,255,.03); }\n[data-theme=\"dark\"] th.cb-th:hover { background: #1a2840 !important; color: var(--muted) !important; }\n[data-theme=\"dark\"] tbody tr.selected { background: #192a42 !important; }\n[data-theme=\"dark\"] tbody tr.selected:hover { background: #1e3350 !important; }\n\n/* Badges / chips hardcodés */\n[data-theme=\"dark\"] .num-badge { background: #1e2d42; color: var(--muted); }\n[data-theme=\"dark\"] .bloc-chip.other { background: #1e2d42; color: var(--muted); }\n[data-theme=\"dark\"] .note-badge { background: #1e2d42; color: var(--muted); }\n[data-theme=\"dark\"] .act-btn.edit:hover { background: rgba(37,87,199,.18); color: #93b4ff; }\n[data-theme=\"dark\"] .act-btn.del:hover  { background: rgba(220,38,38,.15); }\n\n/* Performer list */\n[data-theme=\"dark\"] .performer-item:hover { background: rgba(255,255,255,.04); }\n\n/* Modal & formulaires */\n[data-theme=\"dark\"] .modal { border-color: rgba(255,255,255,.08); }\n[data-theme=\"dark\"] .confirm-dialog { border-color: rgba(255,255,255,.06); }\n[data-theme=\"dark\"] .form-group input,\n[data-theme=\"dark\"] .form-group select { background: #1a2840; color: var(--text); border-color: var(--border); }\n[data-theme=\"dark\"] .form-group input:focus,\n[data-theme=\"dark\"] .form-group select:focus { background: #1e3050; }\n[data-theme=\"dark\"] .btn-cancel { background: #1e2d42; color: var(--muted); }\n[data-theme=\"dark\"] .btn-cancel:hover { background: #243548; }\n\n/* Count badge / search */\n[data-theme=\"dark\"] .count-badge { background: var(--card); border-color: var(--border); color: var(--muted); }\n[data-theme=\"dark\"] .search-wrap input { background: var(--card); }\n[data-theme=\"dark\"] .sort-select { background: var(--card); color: var(--text); border-color: var(--border); }\n\n/* Mobile bottom nav */\n[data-theme=\"dark\"] .mobile-bottom-nav {\n    background: rgba(15,25,35,.97);\n    border-top-color: rgba(255,255,255,.06);\n}\n\n/* Bulk bar fields */\n[data-theme=\"dark\"] .bulk-field-hint { background: #1e2d42; border-color: var(--border); color: var(--muted); }\n[data-theme=\"dark\"] .bulk-field-input { background: #1e2d42; color: var(--text); }\n[data-theme=\"dark\"] .bulk-field-input:not(:disabled):focus { background: #243548; }\n[data-theme=\"dark\"] .bulk-field-input:disabled { background: #141f2e; }\n\n/* Scan modal */\n[data-theme=\"dark\"] .scan-tabs { background: #1e2d42; }\n[data-theme=\"dark\"] .scan-tab.active { background: #243548; color: var(--text); }\n[data-theme=\"dark\"] .scan-dropzone { background: #1e2d42; border-color: var(--border-mid); }\n[data-theme=\"dark\"] .scan-dropzone:hover, [data-theme=\"dark\"] .scan-dropzone.drag-over { background: #1a2a40; border-color: var(--blue); }\n[data-theme=\"dark\"] .btn-retake { background: #1e2d42; color: var(--muted); }\n[data-theme=\"dark\"] .btn-scan { background: var(--card); color: var(--text-2); border-color: var(--border-mid); }\n[data-theme=\"dark\"] .btn-scan:hover { background: #243548; border-color: var(--blue); color: #93b4ff; }\n\n/* Gallery skeletons */\n[data-theme=\"dark\"] .gallery-skeleton .sk-img,\n[data-theme=\"dark\"] .gallery-skeleton .sk-line { background: linear-gradient(90deg, #1e2d42 25%, #243548 50%, #1e2d42 75%); background-size: 200% 100%; animation: shimmer 1.4s infinite; }\n\n/* Kbd hints bar */\n[data-theme=\"dark\"] .kbd-hints { background: #1a2840; border-color: rgba(255,255,255,.06); }\n[data-theme=\"dark\"] kbd { background: #243548; border-color: rgba(255,255,255,.1); color: var(--muted); }\n\n/* Scrollbar */\n[data-theme=\"dark\"] ::-webkit-scrollbar-thumb { background: rgba(255,255,255,.15); }\n[data-theme=\"dark\"] ::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,.25); }\n\n/* ═══════════════════════ THEME TOGGLE BUTTON ═══════════════════════ */\n.theme-toggle {\n    display: flex; align-items: center; gap: 9px;\n    width: 100%; padding: 8px 11px;\n    background: rgba(255,255,255,.05);\n    border: 1px solid rgba(255,255,255,.06);\n    border-radius: var(--r-sm);\n    color: rgba(255,255,255,.45);\n    font-family: 'Manrope', system-ui, sans-serif;\n    font-size: 12.5px; font-weight: 500;\n    cursor: pointer; margin-top: 8px;\n    transition: background .18s, color .18s;\n    -webkit-tap-highlight-color: transparent;\n}\n.theme-toggle:hover { background: rgba(255,255,255,.09); color: rgba(255,255,255,.75); }\n.theme-toggle svg { width: 15px; height: 15px; flex-shrink: 0; transition: transform .4s var(--spring); }\n.theme-toggle:hover svg { transform: rotate(20deg); }\n.theme-toggle .tt-label { flex: 1; text-align: left; }\n\n/* Mobile theme toggle */\n.mobile-theme-toggle {\n    position: absolute; right: 14px; top: 50%; transform: translateY(-50%);\n    background: rgba(255,255,255,.08);\n    border: 1px solid rgba(255,255,255,.08);\n    border-radius: 50%; width: 32px; height: 32px;\n    display: flex; align-items: center; justify-content: center;\n    cursor: pointer; color: rgba(255,255,255,.6);\n    transition: background .18s, color .18s;\n    -webkit-tap-highlight-color: transparent;\n}\n.mobile-theme-toggle:hover { background: rgba(255,255,255,.15); color: rgba(255,255,255,.9); }\n.mobile-theme-toggle svg { width: 15px; height: 15px; }\n\n/* ═══════════════════════ MOBILE ═══════════════════════ */\n.mobile-header { display: none; }\n.mobile-bottom-nav { display: none; }\n\nhtml, body { overflow-x: hidden; max-width: 100vw; }\n\n@media (max-width: 1100px) {\n    .stats-grid { grid-template-columns: repeat(2, 1fr); }\n    .charts-row { grid-template-columns: 1fr; }\n}\n\n@media (max-width: 768px) {\n    :root { --sidebar-w: 0px; }\n    .sidebar { display: none !important; }\n\n    .main {\n        margin-left: 0;\n        padding: 70px 16px 84px !important;\n        width: 100vw; max-width: 100vw;\n        overflow-x: hidden;\n    }\n\n    /* Top header */\n    .mobile-header {\n        display: flex; align-items: center; justify-content: center;\n        height: 54px;\n        background: linear-gradient(180deg, #0e1c2e, #0B1623);\n        position: fixed; top: 0; left: 0; right: 0; z-index: 100;\n        box-shadow: 0 1px 0 rgba(255,255,255,.05), 0 2px 16px rgba(0,0,0,.28);\n    }\n\n    /* Bottom nav */\n    .mobile-bottom-nav {\n        display: flex; justify-content: space-around; align-items: center;\n        position: fixed; bottom: 0; left: 0; right: 0;\n        height: 66px;\n        background: rgba(255,255,255,.96);\n        backdrop-filter: blur(20px); -webkit-backdrop-filter: blur(20px);\n        border-top: 1px solid rgba(0,0,0,.08);\n        z-index: 100;\n        box-shadow: 0 -4px 24px rgba(0,0,0,.08);\n    }\n    .mobile-bottom-nav a {\n        display: flex; flex-direction: column; align-items: center; justify-content: center;\n        text-decoration: none; color: var(--muted-light);\n        font-size: 10px; font-weight: 600;\n        flex: 1; height: 100%;\n        gap: 4px; position: relative;\n        transition: color .18s;\n        -webkit-tap-highlight-color: transparent;\n    }\n    .mobile-bottom-nav a svg {\n        width: 22px; height: 22px;\n        opacity: .45;\n        transition: opacity .18s, transform .2s var(--spring);\n    }\n    .mobile-bottom-nav a span { transition: color .18s; }\n    .mobile-bottom-nav a.active { color: var(--red); }\n    .mobile-bottom-nav a.active svg { opacity: 1; transform: translateY(-2px); }\n    /* Dot indicator */\n    .mobile-bottom-nav a.active::after {\n        content: '';\n        position: absolute;\n        bottom: 6px;\n        width: 4px; height: 4px;\n        background: var(--red);\n        border-radius: 50%;\n        box-shadow: 0 0 6px rgba(227,53,13,.5);\n    }\n    .mobile-bottom-nav a:active svg { transform: scale(.88); }\n\n    /* Page header */\n    .page-header {\n        flex-direction: row; align-items: center;\n        justify-content: space-between; flex-wrap: nowrap;\n        gap: 12px; margin-bottom: 16px;\n    }\n    .page-header > div:first-child { min-width: 0; flex: 1; }\n    .page-title { font-size: 20px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n    .page-subtitle { display: none; }\n\n    .page-header .btn-add,\n    .page-header .btn-scan {\n        width: auto; padding: 9px 13px; font-size: 12px; flex-shrink: 0;\n    }\n    .page-header .btn-add svg,\n    .page-header .btn-scan svg { width: 14px; height: 14px; }\n\n    /* Stats */\n    .stats-grid { grid-template-columns: 1fr 1fr; gap: 10px; }\n    .stat-card { padding: 14px 14px 12px; }\n    .stat-value { font-size: 20px; }\n    .stat-footer { font-size: 10.5px; }\n    .charts-row { gap: 10px; }\n    .panel { padding: 16px; }\n    .chart-wrap { height: 200px; }\n\n    /* Search bar */\n    .top-bar { flex-direction: row; align-items: center; gap: 8px; }\n    .search-wrap { flex: 1; max-width: 100%; }\n    .bar-right { flex-shrink: 0; }\n    .count-badge { font-size: 11px; padding: 6px 10px; }\n\n    /* TABLE → CARD LIST */\n    .table-wrap {\n        background: transparent;\n        border: none; box-shadow: none;\n        overflow: visible;\n    }\n    table { display: block; width: 100%; }\n    thead { display: none; }\n    tbody { display: flex; flex-direction: column; gap: 10px; }\n\n    tbody tr {\n        display: block;\n        background: var(--card);\n        border-radius: var(--r-lg);\n        border: 1px solid var(--border);\n        box-shadow: var(--sh-sm);\n        padding: 14px 16px;\n        transition: box-shadow .18s, transform .15s;\n    }\n    tbody tr:hover { box-shadow: var(--sh); transform: translateY(-1px); }\n\n    tbody td {\n        display: flex; align-items: center;\n        justify-content: space-between;\n        padding: 5px 0; font-size: 13px; border: none;\n    }\n    tbody td::before {\n        content: attr(data-label);\n        font-size: 10px; font-weight: 700;\n        text-transform: uppercase; letter-spacing: .5px;\n        color: var(--muted-light);\n        flex-shrink: 0; margin-right: 10px;\n    }\n    tbody td.name-cell {\n        font-size: 15px; font-weight: 700;\n        justify-content: flex-start;\n        padding-bottom: 10px;\n        border-bottom: 1px solid var(--border);\n        margin-bottom: 4px;\n    }\n    tbody td.name-cell::before { display: none; }\n    tbody td:last-child {\n        justify-content: flex-end;\n        padding-top: 10px;\n        border-top: 1px solid var(--border);\n        margin-top: 4px;\n    }\n    tbody td:last-child::before { display: none; }\n    .actions { gap: 8px; }\n    .act-btn { width: 38px; height: 38px; border-radius: var(--r-sm); }\n\n    /* Modal : bottom sheet */\n    .modal-overlay { align-items: flex-end; padding: 0; }\n    .modal {\n        margin: 0; width: 100%; max-width: 100%;\n        border-radius: var(--r-xl) var(--r-xl) 0 0;\n        transform: translateY(100%);\n        transition: transform .32s var(--ease-out);\n        padding: 24px 20px 36px;\n        max-height: 92vh; overflow-y: auto;\n        border: none;\n        border-top: 1px solid var(--border);\n    }\n    /* Drag handle */\n    .modal::before {\n        content: '';\n        display: block;\n        width: 36px; height: 4px;\n        background: var(--border-mid);\n        border-radius: 99px;\n        margin: -8px auto 20px;\n    }\n    .modal-overlay.active .modal { transform: translateY(0); }\n    .form-row.wide, .form-row { grid-template-columns: 1fr !important; gap: 0; }\n\n    /* Misc */\n    .date-badge { display: none; }\n    .num-badge { max-width: 110px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }\n\n    /* Scan modal mobile */\n    .scan-modal { width: 100%; }\n}\n\n/* ═══════════════════════ GALLERY VIEW ═══════════════════════ */\n.view-toggle {\n    display: flex; gap: 2px;\n    background: #F0F2F8; border-radius: 8px;\n    padding: 3px; border: 1px solid var(--border);\n}\n.view-btn {\n    display: flex; align-items: center; justify-content: center;\n    width: 30px; height: 28px; border: none; border-radius: 6px;\n    background: transparent; color: var(--muted);\n    cursor: pointer; transition: background .15s, color .15s, box-shadow .15s;\n    -webkit-tap-highlight-color: transparent;\n}\n.view-btn svg { width: 15px; height: 15px; }\n.view-btn.active { background: white; color: var(--blue); box-shadow: var(--sh-sm); }\n.view-btn:not(.active):hover { color: var(--text-2); }\n\n.gallery-grid {\n    display: grid;\n    grid-template-columns: repeat(7, 1fr);\n    gap: 12px; padding: 4px 0 16px;\n}\n@media (max-width: 1400px) { .gallery-grid { grid-template-columns: repeat(6, 1fr); } }\n@media (max-width: 1100px) { .gallery-grid { grid-template-columns: repeat(5, 1fr); } }\n@media (max-width: 860px)  { .gallery-grid { grid-template-columns: repeat(4, 1fr); } }\n@media (max-width: 640px)  { .gallery-grid { grid-template-columns: repeat(3, 1fr); } }\n\n.gallery-card {\n    background: var(--card); border: 1px solid var(--border);\n    border-radius: 12px; overflow: hidden; box-shadow: var(--sh-sm);\n    transition: transform .18s var(--spring), box-shadow .18s;\n    cursor: default; display: flex; flex-direction: column;\n}\n.gallery-card:hover { transform: translateY(-3px) scale(1.02); box-shadow: 0 8px 24px rgba(0,0,0,.12); }\n.gallery-img-wrap {\n    position: relative; aspect-ratio: 3/4;\n    background: linear-gradient(135deg, #EEF2FF 0%, #F5F3FF 100%);\n    overflow: hidden; flex-shrink: 0;\n}\n.gallery-img-wrap img { width: 100%; height: 100%; object-fit: contain; transition: opacity .3s; }\n.gallery-img-wrap img.loading { opacity: 0; }\n.gallery-img-placeholder {\n    position: absolute; inset: 0;\n    display: flex; align-items: center; justify-content: center; color: var(--muted-light);\n}\n.gallery-img-placeholder svg { width: 32px; height: 32px; }\n.gallery-benef-badge {\n    position: absolute; top: 6px; right: 6px;\n    font-size: 10.5px; font-weight: 700; padding: 3px 7px; border-radius: 20px;\n    backdrop-filter: blur(8px); white-space: nowrap;\n}\n.gallery-benef-badge.positive { background: rgba(5,150,105,.15); color: #059669; border: 1px solid rgba(5,150,105,.2); }\n.gallery-benef-badge.negative { background: rgba(220,38,38,.12); color: #dc2626; border: 1px solid rgba(220,38,38,.15); }\n.gallery-benef-badge.neutral  { background: rgba(107,114,128,.1); color: var(--muted); border: 1px solid var(--border); }\n.gallery-note-badge {\n    position: absolute; top: 6px; left: 6px;\n    font-size: 10px; font-weight: 800; padding: 3px 7px; border-radius: 20px;\n    backdrop-filter: blur(8px);\n    background: rgba(245,184,0,.2); color: #b45309; border: 1px solid rgba(245,184,0,.3);\n}\n.gallery-info { padding: 8px 9px 9px; display: flex; flex-direction: column; gap: 2px; flex: 1; }\n.gallery-name {\n    font-size: 11.5px; font-weight: 700; color: var(--text);\n    white-space: nowrap; overflow: hidden; text-overflow: ellipsis; line-height: 1.3;\n}\n.gallery-sub { font-size: 10px; color: var(--muted); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n.gallery-actions { display: flex; gap: 4px; margin-top: 5px; }\n.gallery-act {\n    flex: 1; display: flex; align-items: center; justify-content: center;\n    height: 26px; border: 1px solid var(--border); border-radius: 6px;\n    background: #F6F8FC; color: var(--muted); cursor: pointer;\n    transition: background .15s, color .15s, border-color .15s;\n    -webkit-tap-highlight-color: transparent;\n}\n.gallery-act svg { width: 12px; height: 12px; }\n.gallery-act:hover { background: var(--blue-dim); color: var(--blue); border-color: rgba(37,87,199,.2); }\n.gallery-act.del:hover { background: var(--danger-bg); color: var(--danger); border-color: rgba(220,38,38,.2); }\n\n/* skeleton */\n.gallery-skeleton { background: var(--card); border: 1px solid var(--border); border-radius: 12px; overflow: hidden; box-shadow: var(--sh-sm); }\n.gallery-skeleton .sk-img { aspect-ratio: 3/4; background: linear-gradient(90deg, #f0f2f8 25%, #e4e8f4 50%, #f0f2f8 75%); background-size: 200% 100%; animation: shimmer 1.4s infinite; }\n.gallery-skeleton .sk-line { height: 10px; border-radius: 4px; margin: 8px 9px 3px; background: linear-gradient(90deg, #f0f2f8 25%, #e4e8f4 50%, #f0f2f8 75%); background-size: 200% 100%; animation: shimmer 1.4s infinite; }\n.gallery-skeleton .sk-line.short { width: 55%; margin-top: 0; }\n@keyframes shimmer { to { background-position: -200% 0; } }\n\n/* ═══════════════════════ BULK ACTIONS ═══════════════════════ */\n.cb-wrap { width: 36px; flex-shrink: 0; display: flex; align-items: center; justify-content: center; }\n.row-cb { width: 16px; height: 16px; border: 1.5px solid var(--border-mid); border-radius: 4px; cursor: pointer; accent-color: var(--blue); transition: border-color .15s; }\n.row-cb:hover { border-color: var(--blue); }\nth.cb-th { width: 40px; padding: 12px 8px 12px 16px; cursor: default !important; text-transform: none; }\nth.cb-th:hover { color: var(--muted) !important; background: #F6F8FC !important; }\ntd.cb-td { padding: 13px 8px 13px 16px; width: 40px; }\ntbody tr.selected { background: #EEF4FF !important; }\ntbody tr.selected:hover { background: #E5EDFF !important; }\n\n.bulk-bar {\n    position: fixed; bottom: 28px; left: 50%;\n    transform: translateX(-50%) translateY(120%);\n    background: var(--navy); color: white;\n    border-radius: var(--r-lg); padding: 10px 14px;\n    display: flex; align-items: center; gap: 10px;\n    box-shadow: 0 8px 32px rgba(0,0,0,.32), 0 2px 8px rgba(0,0,0,.18);\n    z-index: 300; transition: transform .35s var(--spring), opacity .25s;\n    opacity: 0; white-space: nowrap;\n    border: 1px solid rgba(255,255,255,.08); min-width: 320px;\n}\n.bulk-bar.visible { transform: translateX(-50%) translateY(0); opacity: 1; }\n.bulk-count { font-size: 12px; font-weight: 700; background: rgba(255,255,255,.12); padding: 4px 10px; border-radius: 20px; color: rgba(255,255,255,.85); margin-right: 4px; font-variant-numeric: tabular-nums; }\n.bulk-btn { display: flex; align-items: center; gap: 6px; padding: 7px 13px; border-radius: var(--r-sm); font-family: 'Manrope', system-ui, sans-serif; font-size: 12.5px; font-weight: 600; border: none; cursor: pointer; transition: background .15s, transform .1s var(--spring); -webkit-tap-highlight-color: transparent; }\n.bulk-btn svg { width: 14px; height: 14px; flex-shrink: 0; }\n.bulk-btn:active { transform: scale(.93); }\n.bulk-btn-ebay  { background: rgba(124,58,237,.22); color: #c4b5fd; }\n.bulk-btn-ebay:hover  { background: rgba(124,58,237,.35); }\n.bulk-btn-edit  { background: var(--blue-dim); color: #93b4ff; }\n.bulk-btn-edit:hover  { background: rgba(37,87,199,.22); }\n.bulk-btn-del   { background: var(--red-dim); color: #fca5a5; }\n.bulk-btn-del:hover   { background: rgba(227,53,13,.22); }\n.bulk-sep { width: 1px; height: 20px; background: rgba(255,255,255,.1); margin: 0 2px; }\n.bulk-close { background: none; border: none; color: rgba(255,255,255,.35); cursor: pointer; padding: 4px; border-radius: 4px; display: flex; align-items: center; justify-content: center; margin-left: 2px; transition: color .15s; }\n.bulk-close:hover { color: rgba(255,255,255,.75); }\n.bulk-close svg { width: 13px; height: 13px; }\n.bulk-progress { height: 3px; background: rgba(255,255,255,.1); border-radius: 2px; margin: 2px 0; width: 100%; display: none; }\n.bulk-progress-bar { height: 100%; background: var(--gold); border-radius: 2px; width: 0%; transition: width .3s; }\n.bulk-edit-modal .modal-head { border-bottom: 1px solid var(--border); }\n.bulk-field-hint { font-size: 11.5px; color: var(--muted-light); background: #F6F8FC; border-radius: var(--r-xs); padding: 8px 12px; margin-bottom: 16px; border: 1px solid var(--border); }\n.bulk-field-row { display: flex; align-items: center; gap: 10px; margin-bottom: 12px; }\n.bulk-field-cb { accent-color: var(--blue); width: 15px; height: 15px; cursor: pointer; flex-shrink: 0; }\n.bulk-field-label { font-size: 11px; font-weight: 700; color: var(--muted); text-transform: uppercase; letter-spacing: .5px; min-width: 110px; }\n.bulk-field-input { flex: 1; padding: 8px 11px; border: 1.5px solid var(--border); border-radius: var(--r-xs); font-family: 'Manrope', system-ui, sans-serif; font-size: 13.5px; color: var(--text); outline: none; background: #fafbfd; transition: border-color .18s, box-shadow .18s; }\n.bulk-field-input:disabled { opacity: .35; cursor: not-allowed; background: #F0F2F8; }\n.bulk-field-input:not(:disabled):focus { border-color: var(--blue); box-shadow: 0 0 0 3px var(--blue-dim); background: var(--card); }\n\n/* ═══════════════════════ SCAN ═══════════════════════ */\n.btn-scan { display: flex; align-items: center; gap: 7px; background: var(--card); color: var(--text-2); border: 1px solid var(--border-mid); padding: 10px 16px; border-radius: var(--r-sm); font-family: 'Manrope', system-ui, sans-serif; font-size: 13px; font-weight: 600; cursor: pointer; transition: background .15s, border-color .15s, color .15s, transform .1s var(--spring); box-shadow: var(--sh-sm); white-space: nowrap; -webkit-tap-highlight-color: transparent; }\n.btn-scan:hover { background: #f0f3ff; border-color: var(--blue); color: var(--blue); }\n.btn-scan:active { transform: scale(.96); }\n.btn-scan svg { width: 15px; height: 15px; }\n.scan-modal { width: 540px; }\n.scan-tabs { display: flex; gap: 6px; background: #F5F7FB; border-radius: var(--r-sm); padding: 4px; margin-bottom: 16px; }\n.scan-tab { flex: 1; display: flex; align-items: center; justify-content: center; gap: 7px; padding: 8px 12px; border: none; border-radius: 7px; font-family: 'Manrope', system-ui, sans-serif; font-size: 12.5px; font-weight: 600; color: var(--muted); background: none; cursor: pointer; transition: background .15s, color .15s, box-shadow .15s; }\n.scan-tab svg { width: 14px; height: 14px; }\n.scan-tab.active { background: var(--card); color: var(--text); box-shadow: var(--sh-sm); }\n.scan-dropzone { display: flex; flex-direction: column; align-items: center; justify-content: center; border: 1.5px dashed var(--border-mid); border-radius: var(--r); padding: 36px 20px; cursor: pointer; gap: 8px; transition: border-color .15s, background .15s; background: #fafbfd; }\n.scan-dropzone:hover, .scan-dropzone.drag-over { border-color: var(--blue); background: #f0f4ff; }\n.scan-drop-icon svg { width: 40px; height: 40px; stroke: var(--muted-light); }\n.scan-drop-text { font-size: 14px; font-weight: 600; color: var(--text-2); }\n.scan-drop-sub { font-size: 12px; color: var(--muted-light); }\n.scan-preview-wrap { display: flex; gap: 10px; flex-wrap: wrap; margin-top: 12px; }\n.scan-preview-item { position: relative; width: 90px; height: 120px; border-radius: var(--r-sm); overflow: hidden; border: 1.5px solid var(--border); box-shadow: var(--sh-sm); }\n.scan-preview-item img { width: 100%; height: 100%; object-fit: cover; }\n.scan-remove { position: absolute; top: 4px; right: 4px; width: 20px; height: 20px; border-radius: 50%; background: rgba(0,0,0,.55); color: white; border: none; cursor: pointer; font-size: 10px; display: flex; align-items: center; justify-content: center; }\n.scan-camera-wrap { position: relative; border-radius: var(--r); overflow: hidden; background: #0B1623; aspect-ratio: 4/3; max-height: 280px; }\n#scanVideo { width: 100%; height: 100%; object-fit: cover; display: block; }\n.scan-camera-overlay { position: absolute; inset: 0; display: flex; align-items: center; justify-content: center; pointer-events: none; }\n.scan-frame { width: 65%; aspect-ratio: 3/4; border: 2px solid rgba(245,184,0,.7); border-radius: 8px; box-shadow: 0 0 0 9999px rgba(0,0,0,.35); }\n.btn-capture { flex: 1; display: flex; align-items: center; justify-content: center; gap: 7px; background: var(--red); color: white; border: none; padding: 10px 18px; border-radius: var(--r-sm); font-family: 'Manrope', system-ui, sans-serif; font-size: 13px; font-weight: 700; cursor: pointer; transition: background .15s, transform .1s var(--spring); }\n.btn-capture:hover { background: var(--red-hover); }\n.btn-capture:active { transform: scale(.96); }\n.btn-capture svg { width: 16px; height: 16px; }\n.btn-retake { display: flex; align-items: center; gap: 7px; background: #EEF0F7; color: var(--muted); border: none; padding: 10px 16px; border-radius: var(--r-sm); font-family: 'Manrope', system-ui, sans-serif; font-size: 13px; font-weight: 600; cursor: pointer; transition: background .15s; }\n.btn-retake svg { width: 14px; height: 14px; }\n.scan-status { display: flex; align-items: center; gap: 10px; padding: 11px 14px; border-radius: var(--r-sm); font-size: 13px; font-weight: 500; background: var(--blue-dim); color: var(--blue); border: 1px solid rgba(37,87,199,.12); margin-top: 12px; }\n.scan-status.error { background: var(--danger-bg); color: var(--danger); border-color: rgba(220,38,38,.12); }\n.scan-status.success { background: var(--success-bg); color: var(--success); border-color: rgba(5,150,105,.12); }\n.scan-status svg { width: 16px; height: 16px; flex-shrink: 0; }\n\n/* ═══════════════════════ TOAST ═══════════════════════ */\n.toast-container { position: fixed; bottom: 24px; right: 24px; display: flex; flex-direction: column; gap: 8px; z-index: 9999; pointer-events: none; }\n.toast { display: flex; align-items: flex-start; gap: 11px; background: var(--navy); color: rgba(255,255,255,.92); padding: 13px 16px; border-radius: var(--r-lg); font-size: 13px; font-weight: 500; line-height: 1.45; box-shadow: 0 8px 32px rgba(0,0,0,.28), 0 2px 8px rgba(0,0,0,.14); min-width: 260px; max-width: 340px; border: 1px solid rgba(255,255,255,.07); pointer-events: auto; animation: toastIn .4s var(--spring) both; position: relative; overflow: hidden; }\n.toast.removing { animation: toastOut .25s ease both; }\n.toast-icon { flex-shrink: 0; margin-top: 1px; }\n.toast-icon svg { width: 16px; height: 16px; }\n.toast.success .toast-icon { color: #34d399; }\n.toast.error   .toast-icon { color: #f87171; }\n.toast.info    .toast-icon { color: #93b4ff; }\n.toast-progress { position: absolute; bottom: 0; left: 0; height: 2px; border-radius: 0 0 var(--r-lg) var(--r-lg); animation: toastProgress 4s linear both; }\n.toast.success .toast-progress { background: #34d399; }\n.toast.error   .toast-progress { background: #f87171; }\n.toast.info    .toast-progress { background: #93b4ff; }\n@keyframes toastIn { from { opacity: 0; transform: translateX(24px) scale(.95); } to { opacity: 1; transform: none; } }\n@keyframes toastOut { from { opacity: 1; } to { opacity: 0; transform: translateX(24px); } }\n@keyframes toastProgress { from { width: 100%; } to { width: 0; } }\n\n/* ═══════════════════════ CONFIRM DIALOG ═══════════════════════ */\n.confirm-overlay { position: fixed; inset: 0; background: rgba(11,22,35,.45); z-index: 500; display: flex; align-items: center; justify-content: center; backdrop-filter: blur(8px); -webkit-backdrop-filter: blur(8px); opacity: 0; pointer-events: none; transition: opacity .2s; }\n.confirm-overlay.active { opacity: 1; pointer-events: auto; }\n.confirm-dialog { background: var(--card); border-radius: var(--r-xl); padding: 28px 28px 22px; width: 360px; max-width: 90vw; box-shadow: var(--sh-xl); border: 1px solid rgba(255,255,255,.9); transform: scale(.94) translateY(-8px); transition: transform .28s var(--spring); }\n.confirm-overlay.active .confirm-dialog { transform: scale(1) translateY(0); }\n.confirm-title { font-size: 17px; font-weight: 800; color: var(--text); margin-bottom: 8px; }\n.confirm-body  { font-size: 13.5px; color: var(--muted); margin-bottom: 22px; line-height: 1.55; }\n.confirm-actions { display: flex; justify-content: flex-end; gap: 8px; }\n\n/* ═══════════════════════ MOBILE additions ═══════════════════════ */\n@media (max-width: 768px) {\n    .bulk-bar { bottom: 78px; min-width: min(320px, 92vw); flex-wrap: wrap; }\n    .toast-container { bottom: 78px; right: 12px; left: 12px; }\n    .toast { min-width: auto; max-width: 100%; }\n    .scan-modal { width: 100%; }\n    .gallery-grid { gap: 8px; }\n}\n";
